// Voronoi Pulse -- organic cells, audio color, feedback trails
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.80; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

voronoi(5, 0.15, 0.4)
  .color(
    () => 0.7 + low() * 0.6,
    () => 0.5 + mid() * 0.5,
    () => 1.0 + high() * 0.3
  )
  .rotate(() => time * 0.015)
  .modulate(noise(2, 0.15), () => 0.08 + low() * 0.008)
  .blend(
    osc(10, 0.05, 1.6)
      .color(
        () => 0.5 + mid() * 0.4,
        () => 0.8 + high() * 0.3,
        () => 0.3 + low() * 0.4
      )
      .modulate(voronoi(8, 0.1, 0.3), 0.06),
    0.3
  )
  .blend(src(o0).rotate(() => Math.sin(time * 0.04) * 0.003).hue(() => amp() * 0.005), 0.8)
  .saturate(() => 1.2 + mid() * 0.4)
  .colorama(() => 0.001 + amp() * 0.003)
  .hue(() => high() * 0.012)
  .contrast(() => 1.04 + low() * 0.07)
  .brightness(0.025)
  .out(o0)
